head.script:
scwin.gubunFlag = false;
//-------------------------------------------------------------------------
// function name : f_OnLoad
// function desc : 화면로딩시 
//-------------------------------------------------------------------------
scwin.onpageload = function() {
    $c.gus.cfDisableObjects([ ed_txt_prdyr, ed_txt_vehclNo, ed_txt_drcrNo, ed_txt_degNm, ed_txt_degForm, acb_eqNrmCd, ed_txt_stdFleffcncy
					        , acb_lux_bizTypCd, acb_lux_trfAdptCd, ed_txt_outBranch, ica_em_inspDt1, ica_em_inspDt2
                            , acb_lux_degClsCd, ica_em_degDt, ica_em_firstRegDt, ica_em_chkDt, rd_useYn, ed_txt_rmk ]);

    const codeOptions = [
        { grpCd : "JA060", compID : "acb_eqNrmCd,gr_results:ton" }
      , { grpCd : "JA010", compID : "acb_lux_cond_bizTypCd,acb_lux_bizTypCd" }
      , { grpCd : "JA080", compID : "acb_lux_trfAdptCd" }
      , { grpCd : "JA090", compID : "acb_lux_degClsCd" }
    ];
    $c.data.setCommonCode(codeOptions);
};

//-------------------------------------------------------------------------
// 화면로딩시 UDC 호출
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function () {
    $c.gus.cfDisableObjects([ ed_clntNo_rslts, txt_clntNm_rslts ]);
};

//-------------------------------------------------------------------------
// 조회조기 필드 Clear
//-------------------------------------------------------------------------
scwin.btn_fieldClear_onclick = function (e) {
    $c.gus.cfInitObjects(tbl_cndArea, []);
};

//-------------------------------------------------------------------------
// function name : f_Retrieve
// function desc : 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onclick = function (e) {
    ds_results.removeAll();
	ds_incidentalExpenses.removeAll();

    $c.sbm.execute(sbm_retrieve);
};

scwin.sbm_retrieve_submitdone = function (e) {
    if( e.responseJSON.resultDataSet[0].Code == 0 ) {
        totalRowsResults.setValue(ds_results.getRowCount());
        if( ds_results.getRowCount() == 0 ) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_002);
            return false;
        } else {
            $c.gus.cfDisableObjects([btn_clntNo_rslts]);
            gr_results.setFocusedCell(0, 0);
            ds_results.setRowPosition(0);
        }
    }
};

scwin.sbm_retrieve_submit = function (e) {
    dma_condition.set("clntNo", ed_clntNo.getValue());
    dma_condition.set("vehclNo", vehclNo.getValue());
    dma_condition.set("bizTypCd", acb_lux_cond_bizTypCd.getValue());
};

//-------------------------------------------------------------------------
// function name : f_retrieve_incExpense
// function desc : 용차료 및 부대비용 정보
//-------------------------------------------------------------------------
scwin.f_retrieve_incExpense = function () {
	dma_cond_incidentalExpenses.set("eqCd", ds_results.getCellData(ds_results.getRowPosition(), "eqCd"));
    $c.sbm.execute(sbm_retrieve_incExpense);
}

scwin.sbm_retrieve_incExpense_submitdone = function (e) {
    if( e.responseJSON.resultDataSet[0].Code == 0 ) {
        totalRows.setValue(gr_incidentalExpenses.getRowCount());
        if( ds_incidentalExpenses.getRowCount() > 0 ) {
            ds_incidentalExpenses.setRowPosition(0);
            gr_incidentalExpenses.setFocusedCell(0, 0);
        }
    }
};

//-------------------------------------------------------------------------
// function name : f_Save
// function desc : 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = async function () {

    for( var i = 0; i < ds_incidentalExpenses.getRowCount(); i++ ) {
   		if( ds_incidentalExpenses.getRowStatus(i) == "C" || ds_incidentalExpenses.getRowStatus(i) == "D" || ds_incidentalExpenses.getRowStatus(i) == "U" ) {
   			if(ds_incidentalExpenses.getCellData(i, "adptYm") == "" &&  ds_incidentalExpenses.getCellData(i, "adptStDt") == "" ) {
   				$c.win.alert((i+1)+"번재 행의 적용년월 또는 적용기간은 필수 입력 항목 입니다.");
   				return false;
   			}
   			if(ds_incidentalExpenses.getCellData(i, "adptYm") == "" 
   			  && (ds_incidentalExpenses.getCellData(i, "adptStDt") == "" || ds_incidentalExpenses.getCellData(i, "adptEndDt") == "" ) ) {
   				$c.win.alert((i+1)+"번재 행의  적용기간의 FROM,TO는  필수 입력 항목 입니다.");
   				return false;
   			}
   			if(ds_incidentalExpenses.getCellData(i, "clntNo") == ""){
   				$c.win.alert((i+1)+"번째 행의 거래처 정보를 등록해 주십시오.");
   				return false;
   			}
   			if(ds_incidentalExpenses.getCellData(i, "selpchItemCd") == ""){
   				$c.win.alert((i+1)+"번째 행의 청구/정산 정보를 등록해 주십시오.");
   				return false;
   			}
   			if(ds_incidentalExpenses.getCellData(i, "amtWcrc") == ""){
   				$c.win.alert((i+1)+"번째 행의 금액을 등록해 주십시오.");
   				return false;
   			}
   			if(ds_incidentalExpenses.getCellData(i, "deductYn") == 1){
   				if(ds_incidentalExpenses.getCellData(i, "adptDeg") == ""){
   					$c.win.alert((i+1)+"번째 행의 적용차수을 등록해 주십시오.");
   					return false;
   				}
   				if(ds_incidentalExpenses.getCellData(i, "allDeg") == ""){
   					$c.win.alert((i+1)+"번째 행의 전체차수을 등록해 주십시오.");
   					return false;
   				}
   				if(ds_incidentalExpenses.getCellData(i, "adptTerm") == ""){
   					$c.win.alert((i+1)+"번째 행의 적용기간을 등록해 주십시오.");
   					return false;
   				}
   			}
   		}
   	}

    let confirm = await $c.win.confirm(MSG_CM_CRM_001);
	if (confirm) {
        $c.sbm.execute(sbm_save);
	}
};

scwin.sbm_save_submitdone = function (e) {
    if ( e.responseJSON.resultDataSet[0].Code == 0 ) {
        $c.gus.cfAlertMsg(MSG_CM_INF_001);	// 성공적으로 저장하였습니다
	    scwin.btn_retrieve_onclick();
    }
};

//-------------------------------------------------------------------------
// 행복사 버튼 기능
//-------------------------------------------------------------------------
scwin.btn_copy_onclick = function (e) {
	if( ds_incidentalExpenses.getRowCount() == 0 ) {
		return false;
	} else {
        var curRow = ds_incidentalExpenses.getRowPosition(); // 현재 포커스된 행 번호
        var rowData = ds_incidentalExpenses.getRowJSON(curRow); // 현재 행의 데이터를 JSON 형태로 추출
        var newRow = ds_incidentalExpenses.insertRow(ds_incidentalExpenses.getRowCount()); // 맨 끝에 빈 행 추가
        let rowIndex = ds_incidentalExpenses.getRowCount()-1;
        gr_incidentalExpenses.setFocusedCell(rowIndex, 0);

        ds_incidentalExpenses.setRowJSON(newRow, rowData, true); // 추출한 데이터를 새 행에 붙여넣기
        totalRows.setValue(ds_incidentalExpenses.getRowCount());
    }
};

//-------------------------------------------------------------------------
// 행추가 버튼 기능
//-------------------------------------------------------------------------
scwin.rowAddFunction = function () {
    if( ds_results.getRowCount() == 0 ) {
        return false;
    }

    ds_incidentalExpenses.insertRow();
    let rowIndex = ds_incidentalExpenses.getRowCount()-1;
    gr_incidentalExpenses.setFocusedCell(rowIndex, 0);

    ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "eqCd", ds_results.getCellData(ds_results.getRowPosition(), "eqCd"));
	ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "selpchClsCd", "2");
    ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "deductYn", "0");
    ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "amtWcrc", 0);
    ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "adptDeg", 0);
    ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "allDeg", 0);
    ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "adptTerm", 0);

    totalRows.setValue(ds_incidentalExpenses.getRowCount());
};

//-------------------------------------------------------------------------
// 행삭제 버튼 기능
//-------------------------------------------------------------------------
scwin.rowDelFunction = function () {
    row = gr_incidentalExpenses.getFocusedRowIndex();
    if (ds_incidentalExpenses.getRowStatus(row) == "C") {
        ds_incidentalExpenses.removeRow(row);
        totalRows.setValue(ds_incidentalExpenses.getRowCount());
        return;
    }
    ds_incidentalExpenses.setCellData(row, "chk", "1");
    ds_incidentalExpenses.modifyRowStatus(row, "D");
    totalRows.setValue(ds_incidentalExpenses.getRowCount());
};

//-------------------------------------------------------------------------
// 취소 버튼 기능
//-------------------------------------------------------------------------
scwin.cancelFunction = function () {
    row = gr_incidentalExpenses.getFocusedRowIndex();
    if (ds_incidentalExpenses.getRowStatus(row) == "C") {
        ds_incidentalExpenses.removeRow(row);
        totalRows.setValue(ds_incidentalExpenses.getRowCount());
        return;
    }
    ds_incidentalExpenses.undoRow(gr_incidentalExpenses.getFocusedRowIndex());
    gr_incidentalExpenses.setFocusedCell(0, 0);
    totalRows.setValue(ds_incidentalExpenses.getRowCount());
};

scwin.gr_results_oncellindexchange = function (rowIndex, columnIndex, oldRow, oldColumnIndex) {
    scwin.f_retrieve_incExpense();
};

scwin.gr_incidentalExpenses_oncellindexchange = async function (row, columnIndex, oldRow, oldColumnIndex) {
    //운송비조회
    var colid = gr_incidentalExpenses.getColumnID(columnIndex);

	if (colid == "deductYn"){
        scwin.gubunFlag = true;
		dsResultsRow = ds_results.getRowPosition();
		if (ds_incidentalExpenses.getCellData(row, "selpchClsCd") == "1"){
			ds_cond_trfAmt.set("clntNo", ds_incidentalExpenses.getCellData(row, "clntNo"));
        } else {
			ds_cond_trfAmt.set("clntNo", ds_results.getCellData(dsResultsRow, "clntNo"));
		}

		ds_cond_trfAmt.set("bizTypCd", ds_results.getCellData(dsResultsRow, "bizTypCd"));
		ds_cond_trfAmt.set("ton", ds_results.getCellData(dsResultsRow, "ton"));		
		ds_cond_trfAmt.set("chkClntNo", ds_incidentalExpenses.getCellData(row, "clntNo"));
		ds_cond_trfAmt.set("eqCd", ds_results.getCellData(dsResultsRow, "eqCd"));
		ds_cond_trfAmt.set("selpchClsCd", ds_incidentalExpenses.getCellData(row, "selpchClsCd"));

        await $c.sbm.execute(sbm_retrieve_trfAmt);
	}
};

scwin.f_openCommonPopUp = async function (disGubun, pCode, pName) {
    switch (disGubun) {
        case 1:
            udc_comCode_Grid.setSelectId("retrieveSubsidaryClntListJa");
            udc_comCode_Grid.cfCommonPopUp(scwin.udc_comCode_Grid1_callBackFunc    // XML상의 SELECT ID
							        ,pCode					// 화면에서의 ??? Code Element의	Value
							        ,pName					// 화면에서의 ??? Name Element의	Value
							        ,'T'					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
							        ,'5'					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
							        ,null					// Title순서
							        ,'150,170'  		    // 보여주는 각 컬럼들의 폭
							        ,null					// 컬럼중에서 숨기는	컬럼 지정
							        ,null				// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
							        ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
							        ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이
							        ,null					// 윈도우 위치 Y좌표
							        ,null					// 윈도우 위치 X좌표
							        ,null					// 중복체크여부	("F")
							        ,'F'				    // 전체검색허용여부	("F")
							        ,"거래처,거래처코드,거래처명"	// POP-UP Window Title 검색어1,2 ("Win타이틀,첫번검색Nm,두번?검색Nm")
							       );
			break;

		case 2:
            udc_comCode_Grid.setSelectId("retrieveSelpchItemInfo");
			udc_comCode_Grid.cfCommonPopUp(scwin.udc_comCode_Grid2_callBackFunc  // XML상의 SELECT ID
									,pCode					// 화면에서의 ??? Code Element의	Value
									,pName					// 화면에서의 ??? Name Element의	Value
									,'T'					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
									,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
		  							,null					// Title순서
		  							,null					// 보여주는 각 컬럼들의 폭
		  							,null					// 컬럼중에서 숨기는	컬럼 지정
		  							,null				// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
		  							,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
		  							,null					// POP-UP뛰을때 우도우의	사용자 정의	높이
		  							,null					// 윈도우 위치 Y좌표
		  							,null					// 윈도우 위치 X좌표
									,null                   // 중복체크여부
									,'F'                   // 전체검색허용여부
									,"매출입항목,항목코드,항목명"                   // POP-UP Window Title 검색어1,2(각화면에서 변경할경우)
		  							); 
			break;
    }
};

scwin.udc_comCode_Grid1_callBackFunc = function (rtnList) {
    if( rtnList != null && rtnList[0] != "N/A" ) {
        //cfSetGridReturnValue(rtnList, ds_incidentalExpenses, row, "clntNo", "clntNm");	
        ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "clntNo", rtnList[0]);
        ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "clntNm", rtnList[1]);
    }
};

scwin.udc_comCode_Grid2_callBackFunc = function (rtnList) {
    if( rtnList != null && rtnList[0] != "N/A" ) {
        ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "selpchItemCd", rtnList[0]);	//매출항목ID
        ds_incidentalExpenses.setCellData(ds_incidentalExpenses.getRowPosition(), "selpchItemNm", rtnList[1]);	//매출항목명
    }
};

// 조회조건 : 소속거래처 팝업 기능
scwin.udc_clntNo_onblurCodeEvent = function (e) {
    scwin.udc_clntNo_openPopup('T');
};

scwin.udc_clntNo_onviewchangeNameEvent = function (info) {
    scwin.udc_clntNo_openPopup('T');
};

scwin.udc_clntNo_onclickEvent = function (e) {
    scwin.udc_clntNo_openPopup('F');
};

scwin.udc_clntNo_openPopup = function (pClose) {
    let pCode = ed_clntNo.getValue();
    let pName = txt_clntNm.getValue();
    let pAllSearch = "F";
    let condition = "";
    if( cbx_cnd_chb_repClntYn.getValue() == 1 ) {
        condition = "RP";
    }

    udc_clntNo.cfCommonPopUp(scwin.udc_clntNo_callBackFunc	    // XML상의 SELECT ID
                                ,pCode							// 화면에서의 ??? Code Element의	Value
                                ,pName							// 화면에서의 ??? Name Element의	Value
                                ,pClose							// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                ,'5'							// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                ,null							// Title순서
                                ,'150,170'  		    		// 보여주는 각 컬럼들의 폭
                                ,null							// 컬럼중에서 숨기는 컬럼 지정
                                ,condition						// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                ,null							// POP-UP뛰을때 원도우의	사용자 정의	폭
                                ,null							// POP-UP뛰을때 우도우의	사용자 정의	높이
                                ,null							// 윈도우 위치 Y좌표
                                ,null							// 윈도우 위치 X좌표
                                ,null							// 중복체크여부	("F")
                                ,pAllSearch						// 전체검색허용여부	("F")
                                ,"거래처,거래처코드,거래처명"	  // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                );
};

scwin.udc_clntNo_callBackFunc = function (rtnList) {
    if( rtnList != null && rtnList[0] != "N/A" ) { 
        ed_clntNo.setValue(rtnList[0]); // 코드
        txt_clntNm.setValue(rtnList[1]); // 명
    } else {
        ed_clntNo.setValue(""); // 코드
        txt_clntNm.setValue(""); // 명
    }
};

// 조회조건 : 차량번호 팝업 기능
scwin.udc_vehclNoCd_onblurCodeEvent = function (e) {
    scwin.udc_vehclNoCd_openPopup('T');
};

scwin.udc_vehclNoCd_onviewchangeNameEvent = function (info) {
    scwin.udc_vehclNoCd_openPopup('T');
};

scwin.udc_vehclNoCd_onclickEvent = function (e) {
    scwin.udc_vehclNoCd_openPopup('F');
};

scwin.udc_vehclNoCd_openPopup = function (pClose) {
    let pCode = ed_vehclNoCd.getValue();
    let pName = txt_cond_vehclNo.getValue();
    let pAllSearch = "T";

    udc_vehclNoCd.cfCommonPopUp(scwin.udc_vehclNoCd_callBackFunc	    // XML상의 SELECT ID	
                                ,pCode								    // 화면에서의 ??? Code Element의	Value
                                ,pName								    // 화면에서의 ??? Name Element의	Value
                                ,pClose								    // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                ,'5'                   				    // 검색 결과    컬럼의 보여주는 개수 (SELECT절의 순서) MAX:10 - default (2)
                                ,null                   			    // Title순서    
                                ,null                   			    // 보여주는 각 컬럼들의 폭  
                                ,null                   			    // 컬럼중에서 숨기는    컬럼 지정   
                                ,"022"                   		        // SQL절의 WHERE절에    원하는 조건을 선택함 MAX:8개까지 가능
                                ,null                   			    // POP-UP뛰을때 원도우의    사용자 정의 폭
                                ,null                   			    // POP-UP뛰을때 우도우의    사용자 정의 높이    
                                ,null                   			    // 윈도우 위치 Y좌표    
                                ,null                   			    // 윈도우 위치 X좌표
                                ,null                   			    // 중복체크여부 ("F")
                                ,pAllSearch                 		    // 전체검색허용여부 ("F")
                                ,"차량번호,차량단축코드,차량번호"     // POP-UP Window Title 검색어1,2     ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                );
};

scwin.udc_vehclNoCd_callBackFunc = function (rtnList) {
    if( rtnList != null && rtnList[0] != "N/A" ) { 
        ed_vehclNoCd.setValue(rtnList[0]); // 코드
        txt_cond_vehclNo.setValue(rtnList[1]); // 명
    } else {
        ed_vehclNoCd.setValue(""); // 코드
        txt_cond_vehclNo.setValue(""); // 명
    }
};

// 차량정보 Grid : 소속거래처 팝업 기능
scwin.udc_clntNo_rslts_onblurCodeEvent = function (e) {
    scwin.udc_clntNo_rslts_openPopup('T');
};

scwin.udc_clntNo_rslts_onviewchangeNameEvent = function (info) {
    scwin.udc_clntNo_rslts_openPopup('T');
};

scwin.udc_clntNo_rslts_onclickEvent = function (e) {
    scwin.udc_clntNo_rslts_openPopup('F');
};

scwin.udc_clntNo_rslts_openPopup = function (pClose) {
    let pCode = ed_clntNo_rslts.getValue();
    let pName = txt_clntNm_rslts.getValue();
    let pAllSearch = "F";

    udc_clntNo_rslts.cfCommonPopUp(scwin.udc_clntNo_rslts_callBackFunc	    // XML상의 SELECT ID
                                    ,pCode							// 화면에서의 ??? Code Element의	Value
                                    ,pName							// 화면에서의 ??? Name Element의	Value
                                    ,pClose							// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                    ,'5'							// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null							// Title순서
                                    ,'150,170'  		    		// 보여주는 각 컬럼들의 폭
                                    ,null							// 컬럼중에서 숨기는	컬럼 지정
                                    ,null							// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null							// POP-UP뛰을때 원도우의	사용자 정의	폭
                                    ,null							// POP-UP뛰을때 우도우의	사용자 정의	높이
                                    ,null							// 윈도우 위치 Y좌표
                                    ,null							// 윈도우 위치 X좌표
                                    ,null							// 중복체크여부	("F")
                                    ,pAllSearch						// 전체검색허용여부	("F")
                                    ,"거래처,거래처코드,거래처명"	  // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                    );
};

scwin.udc_clntNo_rslts_callBackFunc = function (rtnList) {
    if( rtnList != null && rtnList[0] != "N/A" ) { 
        ed_clntNo_rslts.setValue(rtnList[0]); // 코드
        txt_clntNm_rslts.setValue(rtnList[1]); // 명
    } else {
        ed_clntNo_rslts.setValue(""); // 코드
        txt_clntNm_rslts.setValue(""); // 명
    }
};

// 용차료 및 부대비용 정보 그리드 거래처 or 항목코드 팝업
// selpchItemCd 항목코드
scwin.gr_incidentalExpenses_ontextimageclick = function (rowIndex, columnIndex) {
    let colid = gr_incidentalExpenses.getColumnID(columnIndex);
    if(colid == "clntNo") { // clntNo 거래처코드
        let clntNo = ds_incidentalExpenses.getCellData(rowIndex, "clntNo");
        scwin.f_openCommonPopUp(1, clntNo, "");
    }

    if(colid == "selpchItemCd") { // selpchItemCd 항목코드
        let selpchItemCd = ds_incidentalExpenses.getCellData(rowIndex, "selpchItemCd");
        scwin.f_openCommonPopUp(2, selpchItemCd, "");
    }
};

scwin.gr_incidentalExpenses_onafteredit = async function (row, columnIndex, value) {
    var colid = gr_incidentalExpenses.getColumnID(columnIndex);
    if (colid == "clntNo") {
        var clntNo = ds_incidentalExpenses.getCellData(row, "clntNo");
        if (clntNo == "") {
            ds_incidentalExpenses.setCellData(row, "clntNo", "");
            return false;
        }
        scwin.f_openCommonPopUp(1, clntNo, "");
    }

    if (colid == "selpchItemCd") {
        var selpchItemCd = ds_incidentalExpenses.getCellData(row, "selpchItemCd");
        if (selpchItemCd == "") {
            ds_incidentalExpenses.setCellData(row, "selpchItemCd", "");
            return false;
        }
        scwin.f_openCommonPopUp(2, selpchItemCd, "");
    }

    if (colid == "selpchClsCd") {
		var dsResultsRow = ds_results.getRowPosition();
		if (ds_incidentalExpenses.getCellData(row, "selpchClsCd") == "1"){
			ds_cond_trfAmt.set("clntNo", ds_incidentalExpenses.getCellData(row, "clntNo"));
		} else {
			ds_cond_trfAmt.set("clntNo", ds_results.getCellData(dsResultsRow, "clntNo"));
		}

		ds_cond_trfAmt.set("bizTypCd", ds_results.getCellData(dsResultsRow, "bizTypCd"));
		ds_cond_trfAmt.set("ton", ds_results.getCellData(dsResultsRow, "ton"));
		ds_cond_trfAmt.set("chkClntNo", ds_incidentalExpenses.getCellData(row, "clntNo"));
		ds_cond_trfAmt.set("eqCd", ds_results.getCellData(dsResultsRow, "eqCd"));
		ds_cond_trfAmt.set("selpchClsCd", ds_incidentalExpenses.getCellData(row, "selpchClsCd"));

        await $c.sbm.execute(sbm_retrieve_trfAmt);
	}
};

scwin.sbm_retrieve_trfAmt_submitdone = function (e) {
    if (e.responseJSON.resultDataSet[0].Msg == "SUCC"){
        var rRow = ds_results.getRowPosition(); // 차량List
        var iRow = ds_incidentalExpenses.getRowPosition(); // 용차료 및 부대비용 정보

        if (scwin.gubunFlag) {
            scwin.gubunFlag = false;
            if (ds_incidentalExpenses.getCellData(iRow, "selpchItemCd") == "1039") { //운송임
                if (ds_trfAmt.getCellData(0, "adptDt") == "") {
                    $c.win.alert("조회된 계약요율이 없습니다.");
                    return false;
                }else{
                    if (ds_incidentalExpenses.getCellData(iRow, "selpchClsCd") == "1"){ //매출
                        ds_incidentalExpenses.setCellData(iRow, "amtWcrc", ds_trfAmt.getCellData(0, "sellAmt"));
                    } else if (ds_incidentalExpenses.getCellData(iRow, "selpchClsCd") == "2"){ //매입
                        if (ds_results.getCellData(rRow, "trfAdptCd") == "01" 
                            || ds_results.getCellData(rRow, "trfAdptCd") == "03"){ //장축
                            ds_incidentalExpenses.setCellData(iRow, "amtWcrc", ds_trfAmt.getCellData(0, "pchsLongAmt"));
                        }else if (ds_results.getCellData(rRow,"trfAdptCd") == "02"){
                            ds_incidentalExpenses.setCellData(iRow, "amtWcrc", ds_trfAmt.getCellData(0, "pchsSuperLongAmt"));
                        }
                    }
                    ds_incidentalExpenses.setCellData(iRow, "deductYn", "0"); //공제여부 - no
                }
            }
        } else {
            if (ds_trfAmt.getCellData(0, "chkClntNoExistYn") == "NO" && ds_incidentalExpenses.getCellData(iRow, "clntNo") != "999910"){
                var selpchClsNm = "";
                if (ds_incidentalExpenses.getCellData(iRow, "selpchClsCd") == "1"){
                    selpchClsNm = "청구";
                }else if (ds_incidentalExpenses.getCellData(iRow, "selpchClsCd") == "2"){
                    selpchClsNm = "정산";
                }
                $c.win.alert("거래처 " + ds_incidentalExpenses.getCellData(iRow, "clntNm")
                                    + "는(은) " + ds_results.getCellData(rRow, "vehclNo")
                                    + " 차량의 " + selpchClsNm + "거래처로 등록되지 않았습니다. "
                                    + "차량관리의 거래처별소속차량관리 화면에서 " + selpchClsNm
                                    + "거래처로 등록해 주시기 바랍니다." 
                                    + "공통거래처(999910)은 제약없이 입력 가능합니다." 
                );
                return false;
            }

            if (ds_incidentalExpenses.getCellData(iRow, "selpchItemCd") == "1039") { //운송임
                if (ds_trfAmt.getCellData(0, "adptDt") == "") {
                    $c.win.alert("조회된 계약요율이 없습니다.");
                    return false;
                }else{
                    if (ds_incidentalExpenses.getCellData(iRow, "selpchClsCd") == "1"){ //매출
                        ds_incidentalExpenses.setCellData(iRow, "amtWcrc", ds_trfAmt.getCellData(0, "sellAmt"));
                    } else if (ds_incidentalExpenses.getCellData(iRow, "selpchClsCd") == "2"){ //매입
                        if (ds_results.getCellData(rRow, "trfAdptCd") == "01" 
                            || ds_results.getCellData(rRow, "trfAdptCd") == "03"){ //장축
                            ds_incidentalExpenses.setCellData(iRow, "amtWcrc", ds_trfAmt.getCellData(0, "pchsLongAmt"));
                        }else if (ds_results.getCellData(rRow,"trfAdptCd") == "02"){
                            ds_incidentalExpenses.setCellData(iRow, "amtWcrc", ds_trfAmt.getCellData(0, "pchsSuperLongAmt"));
                        }
                    }
                    ds_incidentalExpenses.setCellData(iRow, "deductYn", "0"); //공제여부 - no
                }
            }
        }
    }
};

