/**
 * @method
 * @name f_RunExcel
 * @description 차량리스트 엑셀 다운로드
 * @param
 * @hidden N
 * @exception 
 * @example ${example}
 */ 
scwin.f_RunExcel = function () {
    const sheetTitle = "차량리스트"
    const options = {
        fileName: sheetTitle + ".xlsx" // [default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        , sheetName: sheetTitle //  엑셀내 시트명 지정필요시
        , headerColor : "#E8E8E8"
        , oddRowBackgroundColor : "#F5FFF5"
        , evenRowBackgroundColor : "#FFFFFF"
        , type : "1"
    };

    const infoArr = [];
    $c.data.downloadGridViewExcel(gr_results, options, infoArr);
};

/**
 * @method
 * @name f_RunExcel2
 * @description 부대비용정보  엑셀 다운로드
 * @param
 * @hidden N
 * @exception 
 * @example ${example}
 */ 
scwin.f_RunExcel2 = function () {
    const sheetTitle = "부대비용정보"
    const options = {
        fileName: sheetTitle + ".xlsx" // [default : excel.xlsx] options.fileName 값이 없을 경우 default값 세팅
        , sheetName: sheetTitle // 엑셀내 시트명 지정필요시
        , headerColor : "#E8E8E8"
        , oddRowBackgroundColor : "#F5FFF5"
        , evenRowBackgroundColor : "#FFFFFF"
        , type : "1"
    };

    const infoArr = [];
    $c.data.downloadGridViewExcel(gr_incidentalExpenses, options, infoArr);
};
